head.script:
//날짜
scwin.curDate = "";
scwin.strDate = "";

scwin.userInfo = "";
scwin.colNmCnt = 0;
//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
    const codeOptions = [
        { grpCd: "ZZ205", compID: "lc_homeClsCd", opt: { "range": "1, EQ" } }
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.curDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.strDate = $c.date.getServerDateTime("yyyyMM");

    //로그인정보 추출
    scwin.userInfo = $c.data.getMemInfo();
};

scwin.ondataload = async function () {
    lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd);// 정비소속구분코드
    if ($c.gus.cfIsNull(scwin.userInfo.eqHomeClsCd)) {
        lc_homeClsCd.setSelectedIndex(0);
    }

    //tobe추가 : asis는 같은 값이 셋팅 되어도 해당 함수 호출하여 추가. 
    await scwin.lc_homeClsCd_onviewchange();

    ds_lux_wrkPlCd.removeAll();
    dma_lux_wrkPlCd.setEmptyValue();

    dma_lux_wrkPlCd.set("param1", lc_homeClsCd.getValue());
    $c.sbm.execute(sbm_lux_wrkPlCd);

    // tobe위치변경 : scwin.sbm_lux_wrkPlCd_submitdone 함수 아래에 작성
    // lux_clsCd.index = 1;
    // lux_calcClsCd.index = 0;

    // em_wrkStDt.focus();
};
//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
    //일자설정
    em_wrkStDt.setValue(scwin.strDate);
    em_wrkEndDt.setValue(scwin.strDate);
};

//for=ds_lux_wrkPlCd event=OnLoadCompleted(rowCnt)
scwin.sbm_lux_wrkPlCd_submitdone = async function (e) {
    lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); //정비작업장코드
    if (lc_wrkPlCd.getSelectedIndex() == -1) lc_wrkPlCd.setSelectedIndex(0);

    lc_clsCd.setSelectedIndex(1);
    lc_calcClsCd.setSelectedIndex(0);

    em_wrkStDt.focus();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if (!await $c.gus.cfValidate([tb_wrk])) return;

    if (em_wrkStDt.getValue() > em_wrkEndDt.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        em_wrkStDt.focus();
        return;
    }

    if (em_wrkStDt.getValue() != em_wrkEndDt.getValue()) {
        if (lc_calcClsCd.getValue() == "1") {
            await $c.win.alert("일자별 조회 시 조회기간은 1개월이어야 합니다.");
            em_wrkEndDt.focus();
            return;
        }
    }

    //ds_fix_work_re.UseChangeInfo = false; // 조회조건

    dma_fix_work_re.set("termFrom", em_wrkStDt.getValue());
    dma_fix_work_re.set("termTo", em_wrkEndDt.getValue());
    dma_fix_work_re.set("fixWrkPlCd", lc_wrkPlCd.getValue());
    dma_fix_work_re.set("clsCd", lc_clsCd.getValue());
    dma_fix_work_re.set("calcClsCd", lc_calcClsCd.getValue());
    dma_fix_work_re.set("bizDomCd", lc_bizDomCd.getValue());

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function (e) {
    var rowCount = ds_fix_work_list.getRowCount();
    ds_fix_work_list.sort("yyMmDd", 0); //원래데이터 정렬

    var clsCd = "";
    var calcClsCd = "";

    clsCd = lc_clsCd.getValue();
    calcClsCd = lc_calcClsCd.getValue();

    ds_crosstab.removeAll(); //초기화

    if (rowCount == 0) {
        await $c.win.alert("조회된 데이터가 없습니다.");
        return;
    } else {
        // ds_crosstab 생성 및  그리드 컬럼생성
        scwin.colNmCnt = 0;

        const nmgroup = [];
        const allData = [];

        let rJson = null;
        let prevKey = "";


        for (let i = 0; i < rowCount; i++) {
            const row = ds_fix_work_list.getRowJSON(i);

            const nm = row.nm;
            const yyMmDd = row.yyMmDd;
            const bizDomNm = row.bizDomNm;
            const planAmt = $c.num.parseInt(row.planAmt) || 0;
            const bilgAmt = $c.num.parseInt(row.bilgAmt) || 0;
            const amt = row.amt;


            if (nmgroup.indexOf(nm) == -1) {
                nmgroup.push(nm);
                if (nmgroup.length > 8) return;
            }

            const nmNum = nm.substring(0, 1);
            const currentKey = bizDomNm + "|" + yyMmDd;


            if (prevKey != currentKey) {
                if (rJson) allData.push(rJson);

                rJson = {
                    yyMmDd,
                    bizDomNm,
                    sumPlanAmt: 0,
                    sumBilgAmt: 0
                };

                prevKey = currentKey;
            }

            // 데이터 세팅 (동적 컬럼)
            rJson[`nm_${nmNum}`] = nm;
            rJson[`planAmt_${nmNum}`] = planAmt;
            rJson[`bilgAmt_${nmNum}`] = bilgAmt;
            rJson[`amt_${nmNum}`] = amt;

            // 합계 누적
            rJson.sumPlanAmt += planAmt;
            rJson.sumBilgAmt += bilgAmt;
        }

        // 마지막 데이터 push
        if (rJson) allData.push(rJson);

        // 데이터 세팅
        ds_crosstab.setJSON(allData);

        // 컬럼 표시  //웹스퀘어는 컬럼동적으로 그릴수 없어 현재 8개(계획, 실적,증감을 한 묶음으로) 그려진 상태에서 항목갯수 만큼 컬럼을 show시켜야함.
        for (let i = 0; i < nmgroup.length; i++) {
            const idx = i + 1;

            gr_work_pl.setColumnVisible(`planAmt_${idx}`, true);
            gr_work_pl.setColumnVisible(`bilgAmt_${idx}`, true);
            gr_work_pl.setColumnVisible(`amt_${idx}`, true);

            gr_work_pl.setHeaderValue(`nm_${idx}`, nmgroup[i].substring(1));
        }

        //그리드 설정 초기화
        gr_work_pl.mergeClear();
        gr_work_pl.setColumnStyle("yyMmDd", "vertical-align", "");
        gr_work_pl.setColumnStyle("yyMmDd", "padding-top", "");
        gr_work_pl.setSubtotalVisible(false);

        if ((clsCd == "1") && (calcClsCd == "1")) {	// 구분 : 사업영역별,  집계구분 : 일자별
            gr_work_pl.setColumnVisible('bizDomNm', true); //사업영역
            gr_work_pl.setColumnDisplayFormat("yyMmDd", "####/##/##");

            //그리드 merge
            gr_work_pl.mergeCellsFixedCols("bycol");
            gr_work_pl.setColumnStyle("yyMmDd", "vertical-align", "text-top");
            gr_work_pl.setColumnStyle("yyMmDd", "padding-top", "4px");

            //그리드 subtotal
            gr_work_pl.setSubtotalVisible(true);

        } else if ((clsCd == "1") && (calcClsCd == "2")) { // 구분 : 사업영역별,  집계구분 : 월별
            gr_work_pl.setColumnVisible('bizDomNm', true); //사업영역
            gr_work_pl.setColumnDisplayFormat("yyMmDd", "####/##");

            //그리드 subtotal
            gr_work_pl.setSubtotalVisible(true);

        } else if ((clsCd == "2") && (calcClsCd == "1")) { // 구분 : 작업장별,  집계구분 : 일자별
            gr_work_pl.setColumnVisible('bizDomNm', false); //사업영역
            gr_work_pl.setColumnDisplayFormat("yyMmDd", "####/##/##");

        } else if ((clsCd == "2") && (calcClsCd == "2")) { // 구분 : 작업장별,  집계구분 : 월별
            gr_work_pl.setColumnVisible('bizDomNm', false); //사업영역
            gr_work_pl.setColumnDisplayFormat("yyMmDd", "####/##");
        }

        gr_work_pl.setVisibleRowNum(15);
    }
};

//-------------------------------------------------------------------------
// 사업역역 콤보 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveBizDomCd = function (param1) {
    ds_combo2.removeAll();

    dma_combo2.set("strVal", param1);
    $c.sbm.execute(sbm_combo2);
};

scwin.sbm_combo2_submitdone = function (e) {
    // 전체조건 추가
    lc_bizDomCd.changeChooseOption("0", "전체");
    lc_bizDomCd.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// 조회 조건 지우기
//-------------------------------------------------------------------------
scwin.f_FieldClear = async function (e) {
    $c.gus.cfInitObjects(tb_wrk, null);

    lc_homeClsCd.setValue(scwin.userInfo.eqHomeClsCd); // 정비소속구분코드

    //tobe추가
    await scwin.lc_homeClsCd_onviewchange();

    if (lc_homeClsCd.getValue() == scwin.userInfo.eqHomeClsCd) {
        lc_wrkPlCd.setValue(scwin.userInfo.fixWrkPlCd); // 정비작업장코드
    }

};

//-------------------------------------------------------------------------
// List 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel1 = function () {
    var count = ds_fix_work_list.getRowCount();
    if (!(count > 0)) return;

    var colSpan =gr_work_pl.getColumnCount()

    var options = {
        fileName: "정비비월별실적집계표.xlsx",
        sheetName: "정비비월별실적집계표",
        startRowIndex: 7,
        startColumnIndex: 0,
        type: 1,
    };

    var infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: "정비비월별실적집계표",
        textAlign: "center",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 2,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `기간 [${$c.date.formatDateTime(em_wrkStDt.getValue(), "yyyy/MM")} ~ ${$c.date.formatDateTime(em_wrkEndDt.getValue(), "yyyy/MM")}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 3,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `정비작업장 [${lc_wrkPlCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 4,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `사업역역 [${lc_bizDomCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 5,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `구분 [${lc_clsCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 6,
        colIndex: 0,
        rowSpan: 1,
        colSpan: colSpan,
        text: `집계 [${lc_calcClsCd.getText(true)}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }];

    $c.data.downloadGridViewExcel(gr_work_pl, options, infoArr);
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.lc_homeClsCd_onviewchange = function (info) {
    ds_lux_wrkPlCd.removeAll();
    var luxIndex = lc_homeClsCd.getValue();

    dma_lux_wrkPlCd.set("param1", luxIndex);
    $c.sbm.execute(sbm_lux_wrkPlCd);

    scwin.f_RetrieveBizDomCd(luxIndex);
};

//-------------------------------------------------------------------------
// gr_work_pl 합계의 증감부분 계산
//-------------------------------------------------------------------------
scwin.sumAmt_customFormatter = function (data, formattedData, rowIndex, colIndex) {
    var calcClsCd = lc_calcClsCd.getValue();
    var rowJson = ds_crosstab.getRowJSON(rowIndex)
    var data = 0;

    if (calcClsCd == "1") { // 집계구분:일자별
        data = $c.num.parseInt(rowJson.amt_1) +
            $c.num.parseInt(rowJson.amt_2) +
            $c.num.parseInt(rowJson.amt_3) +
            $c.num.parseInt(rowJson.amt_4) +
            $c.num.parseInt(rowJson.amt_5) +
            $c.num.parseInt(rowJson.amt_6) +
            $c.num.parseInt(rowJson.amt_7) +
            $c.num.parseInt(rowJson.amt_8)

    } else if (calcClsCd == "2") { // 집계구분:월별
        data = $c.num.parseInt(rowJson.sumBilgAmt) - $c.num.parseInt(rowJson.sumPlanAmt)
    }

    return $c.num.formatNumber(data);
};

scwin.targetV = function (data) {
    var value = "";
    var clsCd = lc_clsCd.getValue(); //구분
    var calcClsCd = lc_calcClsCd.getValue(); //집계구분

    if ((clsCd == "1") && (calcClsCd == "1")) {	// 구분 : 사업영역별,  집계구분 : 일자별
        value = data

    } else if ((clsCd == "1") && (calcClsCd == "2")) { // 구분 : 사업영역별,  집계구분 : 월별
        value = "소계";
    }

    return value;
};
